import { describe, it, expect } from 'vitest'
import { render, screen } from '@testing-library/react'
import { useMantineTheme } from '@mantine/core'
import { AppProviders } from './AppProviders'

/** Renders inside AppProviders and exposes the resolved Mantine theme. */
function ThemeProbe() {
  const theme = useMantineTheme()
  return (
    <div>
      <span data-testid="primary-color">{theme.primaryColor}</span>
      <span data-testid="brand-9">{theme.colors.brand?.[9]}</span>
      <span data-testid="accent-5">{theme.colors.accent?.[5]}</span>
      <span data-testid="font-family">{theme.fontFamily}</span>
    </div>
  )
}

describe('AppProviders', () => {
  it('renders children', () => {
    render(
      <AppProviders>
        <span>hello</span>
      </AppProviders>,
    )
    expect(screen.getByText('hello')).toBeInTheDocument()
  })

  it('wires the production Mantine theme', () => {
    render(
      <AppProviders>
        <ThemeProbe />
      </AppProviders>,
    )

    expect(screen.getByTestId('primary-color').textContent).toBe('brand')
    expect(screen.getByTestId('brand-9').textContent).toBe('#0e1f40')
    expect(screen.getByTestId('accent-5').textContent).toBe('#c9a227')
    expect(screen.getByTestId('font-family')).toHaveTextContent('Inter')
  })

  it('provides brand color shades (not just defaults)', () => {
    render(
      <AppProviders>
        <ThemeProbe />
      </AppProviders>,
    )

    // If the theme were missing, primaryColor would be 'blue' (Mantine default)
    expect(screen.getByTestId('primary-color').textContent).not.toBe('blue')
  })
})

