}

describe('AppProviders', () => {
  it('renders children', () => {
    render(
      <AppProviders>
        <span>hello</span>
      </AppProviders>,
    )
    expect(screen.getByText('hello')).toBeInTheDocument()
  })

  it('wires the production Mantine theme', () => {
    render(
      <AppProviders>
        <ThemeProbe />
      </AppProviders>,
    )

    expect(screen.getByTestId('primary-color').textContent).toBe('brand')
    expect(screen.getByTestId('brand-9').textContent).toBe('#0e1f40')
    expect(screen.getByTestId('accent-5').textContent).toBe('#c9a227')
    expect(screen.getByTestId('font-family')).toHaveTextContent('Inter')
  })

  it('provides brand color shades (not just defaults)', () => {
    render(
      <AppProviders>
        <ThemeProbe />
      </AppProviders>,
    )

    // If the theme were missing, primaryColor would be 'blue' (Mantine default)
    expect(screen.getByTestId('primary-color').textContent).not.toBe('blue')
  })
})

